var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 대균열 지대","JPN":"ロータス、大亀裂地帯","ENG":"Lotus, Grand Dimension Crevice","TWN":"洛德斯，大峽谷地帶"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 5","JPN":"CSE Lv.5","ENG":"CSE Lv. 5","TWN":"CSE Lv.5"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"불경하게도, 왕의 출어를 방해하는 미물들이 남아있었구나.","JPN":"不敬にも、王の御行幸を妨げる微物どもが残っていたとは。","ENG":"How impious. Vermin remain that dare to hinder the queen's outing.","TWN":"真是大不敬，竟然還有廢物阻擋王的出巡。"},"stage":{"bg":"MAINSTREAM_124010","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 충성스러운 병사들아. 왕의 첫번째 사도, 솔리키타티오가 명하겠다.","JPN":"王に忠誠を誓った兵たちよ。王の第一使徒、ソリキタティオが命ずる。","ENG":"Loyal soldiers of the queen. I, Sollicitatio, the queen's first Apostle, command you.","TWN":"王忠誠的士兵們，王的第一使徒，索爾奇塔提奧在此下令。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"우리의 앞을 막는 미물들에게 너희의 충심을 보여주거라.","JPN":"我らの行く手を阻む下等な微物どもに、お前らの忠心を示してみせよ。","ENG":"Show your devotion to the vermin that block our path.","TWN":"向擋在我們面前的廢物展現你們的忠心吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"저, 저게 대체…….","JPN":"あ、あれはいったい……","ENG":"W-what is that...?","TWN":"那、那到底是……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"일단 쏴!","JPN":"とりあえず撃て！","ENG":"Just fire!","TWN":"先開火再說！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"대균열 속에서 뿌리랑 함께 빠져나온 침식체다!","JPN":"大亀裂の中から根と共に現れた侵食体だ！","ENG":"It's a C.O. that rose from the Grand Dimension Crevice with the roots!","TWN":"是連同那些根一起從大峽谷裡爬出來的侵蝕體！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"뭔지는 몰라도 여지껏 마주한 녀석들과는 다를 거야!","JPN":"よくわからないが、おそらく今までのやつらみたいにはいかないはずだ！","ENG":"Whatever it is, it won't be like the ones we've faced so far!","TWN":"不管那是什麼，肯定和之前遇到的不同！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"겁먹은 것을 숨기기 위해 도리어 공격성을 내보이다니.","JPN":"怯えていることを隠すために攻撃性を顕わにするとは。","ENG":"You brandish aggression to hide your fear.","TWN":"為了掩飾自己的恐懼反而展現攻擊性。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"지금 너희들의 모습은…….","JPN":"今の貴様らの姿は……","ENG":"Your current state is...","TWN":"你們現在的模樣……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"사뭇 가축과도 다름이 없구나.","JPN":"まるで家畜そのものだな。","ENG":"No different from livestock.","TWN":"簡直和牲畜沒兩樣。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내 너희를 가엽게 여겨 기꺼이 왕의 병사로 재조립되는 영광을 하사하겠다.","JPN":"貴様らを憐れみ、王の兵として組み直される栄誉を授けよう。","ENG":"I shall pity you and grant the honor of being reassembled as soldiers of the queen.","TWN":"我可憐你們，賞賜你們重鑄為王的士兵的榮耀。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"흐, 흐아아아악!","JPN":"ふ、ふああああっ！","ENG":"N-no!","TWN":"呃、呃啊啊啊啊啊！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"도, 도망…… 도망가야……!","JPN":"に、逃げ……逃げないと……！","ENG":"W-we... We have to run–!","TWN":"快、快逃……快逃啊……！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"이봐! 그쪽으로 가면 안 돼!","JPN":"おい！　そっちに行っちゃダメだ！","ENG":"Hey! Don't go that way!","TWN":"喂！不能往那邊跑！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"흐윽……! 아, 아아아아아아악!","JPN":"ふっ……！　あ、ああああああっ！","ENG":"Ngh...! A-AAAARGH!","TWN":"呃……！啊、啊啊啊啊啊啊！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"애타게 차례를 기다릴 필요는 없다.","JPN":"順番を待つまでもない。","ENG":"No need to wait anxiously for your turn.","TWN":"不必急著想趕快輪到自己。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너희 미물들을 하나하나 정성 들여 재조립할 생각은 없으니.","JPN":"一つ一つ丁寧に組み直してやるほどの価値が、貴様ら微物にあるとでも？","ENG":"I have no intent to reassemble you vermin one by one with care.","TWN":"我可不打算一一重組你們這些廢物。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하나로 반죽해 빚어주마.","JPN":"一塊にして仕上げてやろう。","ENG":"I shall knead you into one mass and mold you.","TWN":"我會把你們揉成一團。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SHADOW_HYPER_ATTACK"},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"좋아! 그럼 이… 유해를 사용하면 차원 계면이 녹아내리는 걸 막을 수 있다는 거지?","JPN":"よし！　じゃあこの……遺骸を利用すると、次元界面が溶けるのを防げるんだよね？","ENG":"Okay! So if we use these... remains, we can stop the dimension surface from melting, right?","TWN":"很好！那麼……只要使用這個遺骸，就能阻止次元界面融解對吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 이 아티팩트의 파장, 원리, 구조를 얼른 파악해서 설계에 반영해야 하고…….","JPN":"ということは、このアーティファクトの波長、原理、構造を早く把握して設計に反映しないと……","ENG":"Then we must grasp the Artifact's wavelength, principle, and structure fast and feed it into the design...","TWN":"那就得趕快分析這個遺物的波長、原理與結構並應用在設計……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"거기! 이볼브 원이랑 기계수집가! 지금 만들고 있는 시스템에 몇 가지를 더 추가해야겠어!","JPN":"そこ！　イボルブ・ワンと機械収集家！　今作ってるシステムに幾つか追加するよ！","ENG":"You there! Evolved One and Machine Collector! We need a few more additions to the system in progress!","TWN":"喂！Evolved One 和機械收藏家！我要在正在建置的系統再加幾個項目！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"인플로전 리액터에 아티팩트의 파장을 가두는 차단막을 설치하고 그 파장이 이터니움의 활성화된 에너지를 안정화시켜서…….","JPN":"インプロージョン・リアクターにアーティファクトの波長を閉じ込めるバリアを張って、その波長が活性化したエタニウムのエネルギーを安定化させ……","ENG":"Install a barrier that traps the Artifact's wavelength in the implosion reactor and use that wavelength to stabilize the activated energy of Eternium...","TWN":"在內爆反應爐加裝能封鎖遺物波長的屏障，讓波長穩定永恆之金活性化後的能量……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이졸데 씨, 저렇게 들뜬 모습은 처음이에요.","JPN":"イゾルデさんがあんなにはしゃいでいる姿、初めて見ます。","ENG":"Isolde, I've never seen you this excited.","TWN":"我第一次看到伊索德這麼興奮的樣子。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"본래 은둔형 외톨이 중에는 자신과 같은 과라고 생각하면 한없이 마음이 열리는 부류가 있다고 합니다.","JPN":"引きこもりの中には、相手が自分と同類だと判断すると一気に心を開くタイプの人がいるらしいです。","ENG":"Among true shut-ins, some open their hearts completely to those they see as their own kind.","TWN":"據說有些隱居型的人只要覺得對方和自己是同類人，就會完全敞開心扉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님은 바로 그 부류에 해당하는 분이십니다.","JPN":"シニア様はまさにそういうタイプです。","ENG":"Senior is exactly that type.","TWN":"Senior就是那種類型的人。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최고 관리자님 앞에서도 까칠하게 굴었지만 결국 자신의 능력을 알아주는 분이셨기에 마음을 열지 않았습니까?","JPN":"最高管理者様の前でも最初は刺々しい態度でしたが、自分の能力を認めてくれる人と知り、心を開いたのです。","ENG":"She was prickly even before the Supreme Administrator, yet opened up because he recognized her ability.","TWN":"即使在最高管理者前全副武裝，最後不也因為對方理解她的才能而敞開心扉了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아마 자신의 능력을 알아주는 사람들이 잔뜩 있는 지금이, 시니어님에겐 천국이나 다름없을 겁니다.","JPN":"そういった人に囲まれている今は、シニア様にとって天国に等しいでしょう。","ENG":"With many people here who appreciate her talents, this must feel like heaven to her.","TWN":"現在滿滿都是知道她能力的人，對Senior來說簡直是天堂吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 사람들이 극악의 범죄자들이란 건…… 시니어님에겐 고려할 바가 아니니까요.","JPN":"相手が極悪非道な犯罪者だという点は……シニア様にとって考慮対象のうちに入りませんから。","ENG":"The fact they are heinous criminals... is not a factor to her.","TWN":"那些人是壞透的罪犯這點……對Senior來說不重要。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하, 하하…… 그렇군요.","JPN":"あ、あはは……そうなんですね。","ENG":"Ha, haha... I see.","TWN":"哈、哈哈……原來如此。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐, 이 정도면 나도 충분히 일을 한 것 같은데.","JPN":"まあ、これだけやれば十分な働きはしただろ。","ENG":"I think I have done enough.","TWN":"嗯，我做到這樣也算盡力了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK"},{"id":"L16_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"나는 이쯤하고 빠지겠어.","JPN":"俺はこの辺で抜けさせてもらうぞ。","ENG":"I'll step out here.","TWN":"我差不多要走了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"빠지겠다고요? 검은 평의회 의장이 우리를 도우라 지시한 게 아닙니까?","JPN":"抜ける？　黒い評議会の議長から私たちを手伝うように指示されているのではなかったんですか？","ENG":"Step out? Did the Dark Council's chair not order you to help us?","TWN":"走？評議會的議長不是命令你幫助我們嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"누가 그런 애늙은이 말을 듣는다고… 나는 너흴 도와주면 아주 좋은 걸 준다고 해서 온 것뿐이야.","JPN":"ませガキの命令など聞くもんか。俺はお前らを手伝ったらいいものをくれるって言われたから来ただけだ。","ENG":"Who ever listens to that old soul...? I came because I was promised something nice if I helped you.","TWN":"誰會聽那老古董的話……我來這裡，只是因為幫你們會拿到很好的獎勵而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"예를 들면… 알파트릭스 회장이 만들어낸 리액터라던가…….","JPN":"たとえば……アルファトリックスの会長が作ったリアクターとか……","ENG":"For example, the reactor the Alphatrix President made...","TWN":"例如……阿爾法崔克斯會長製作的反應爐之類的……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"……아쉽지만, 어쩔 수 없군요.","JPN":"……残念ですが、仕方ありません。","ENG":"...Regrettable, but inevitable.","TWN":"……雖然可惜也沒辦法。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"애초에 임시 동맹이었으니까요.","JPN":"そもそも一時的な同盟でしたからね。","ENG":"This was a temporary alliance in the first place.","TWN":"反正我們本來就只是暫時結盟。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이곳에서 별다른 소동을 일으키지 않은 것만 해도 다행이라 생각합니다.","JPN":"ここで騒ぎを立てずにいてくれただけで、十分ありがたいことだと思います。","ENG":"I will count it a blessing you caused no incident here.","TWN":" 在這裡沒惹事已經是不幸中的大幸了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흥, 이래 보여도 꽤 알아주던 용병이었어.","JPN":"ふん、こう見えて俺は腕利きの傭兵だったんだぞ。","ENG":"Hmph. I was a well-regarded mercenary.","TWN":" 哼，別看我這樣，我也曾是個有名的傭兵。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"내 할당량을 채울 때까진 얌전히 지내는 법 정도는 알고 있다고.","JPN":"自分のノルマを達成するまでは大人しくするもんだってことぐらい心得ているさ。","ENG":"I know how to behave until I meet my quota at least.","TWN":"至少我懂在完成自己的配額前要守分寸這點。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아, 그리고 겸사겸사 시니어의 연구 일지를 내 쪽에 복사해 뒀어.","JPN":"あ、ついでにシニアの研究日誌はコピーさせてもらった。","ENG":"Ah, and by the way, I copied the Senior's research log on my end.","TWN":" 啊，我順便把Senior的研究日誌複製到我那邊了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"천재라 그런지 흥미로운 내용이 많더군.","JPN":"天才なだけあって、なかなか興味深い内容だったな。","ENG":"A lot of it was fascinating, befitting a genius.","TWN":"不愧是天才，裡面有不少有趣的內容呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하, 역시 틈이 생기면 그새를 못 참는군요.","JPN":"はあ、案の定、隙あらば何をやらかすか分からない人ですね。","ENG":"*Sigh* Give you an inch and you just cannot help yourself.","TWN":"哈，果然一有機會你就忍不住下手了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"역시 지금이라도……!","JPN":"今のうちにでも……！","ENG":"Perhaps now we should–!","TWN":"還是現在……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT_ICE"},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내버려둬.","JPN":"ほっておきなさいよ。","ENG":"Leave her be.","TWN":"算了，別管他。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"어차피 마왕을 못 막으면 다 같이 사이좋게 죽을 팔자야.","JPN":"どうせ、魔王を止められなかったらみんな仲良く死ぬんだから。","ENG":"If we can't stop the Demon Lord, we all die together anyway.","TWN":"反正要是無法阻止魔王，大家都要一起面對死亡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저런 사소한 것 가지고 전력을 낭비하고 싶지도 않고.","JPN":"些細なことで戦力を無駄に消耗したくない。","ENG":"I won't waste strength over something that trivial.","TWN":"我才不想為了那種小事浪費戰力。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"게다가 내 연구일지의 가치를 알아봐 주는 사람은 몇 없잖아?","JPN":"それに、私の研究日誌の価値を分かってくれる人なんて、そうそういないでしょ？","ENG":"Besides, few recognize the value of my research log.","TWN":"再說又沒幾個人能看懂我研究日誌的價值？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그러니까 어차피 쓰이기도 전에 사라질 것들이라면 저런 식으로라도 쓰이는 편이 낫다고 생각해…….","JPN":"だ、だから、実を結ぶ前に消えるくらいなら、ああいう形でも使われたほうがマシ……だと思うの。","ENG":"S-So if it would disappear before it could be used, it is better that it gets used like that...","TWN":"所、所以說既然這些遲早會消失的……被利用一下也比較不浪費……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하아, 제가 시니어님의 성격을 잊고 있었군요.","JPN":"はあ……シニア様の性格を忘れていました。","ENG":"*Sigh* I forgot what your personality is like, Senior.","TWN":"哈，我竟然忘了Senior的個性。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저 범죄자의 세 치 혀에 껌뻑 넘어갈 줄이야.","JPN":"あの犯罪者の口車にこうもあっさり乗せられてしまうとは。","ENG":"To think you would fall for that criminal's silver tongue.","TWN":"沒想到會被那罪犯的三寸不爛之舌唬住。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"휘유! 역시 통이 크시다니까, 시니어님은?","JPN":"ひゅー！　さすがシニア、器がデカいな。","ENG":"Whew! You're broad-minded indeed, Senior.","TWN":"呼！我們果然很合得來，Senior？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 알고 있으니까 얼른 작업이나 빨리 끝내자고.","JPN":"ふん、自分でも分かってるし。さっさと作業を終わらせるよ。","ENG":"Hmph. Since you know, hurry and finish the work.","TWN":"哼，知道就好，快點把工作做完吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"너흰 모르겠지만 우린 정말 시간이 촉박할지도 모른다니까!","JPN":"あなたたちはともかく、こっちは本当に時間がないかもしれないんだからね！","ENG":"You may not feel it, but our time might be truly short.","TWN":"你們可能不知道，但我們時間真的不多了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"역시 이런 범죄자들이 칭찬한다고 헤벌쭉하는 걸 보니 제법 너 답네.","JPN":"犯罪者たちに褒められて簡単に口元を緩ませるとは、実にあなたらしいな。","ENG":"Of course you would grin at a criminal's flattery. That's so you.","TWN":"真不愧是你，被這種犯罪者誇個兩句就這麼得意。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"시니어라는 자각이 없는 거야?","JPN":"自分がシニアという自覚がないのか？","ENG":"Do you lack awareness of being a Senior?","TWN":"妳沒有Senior的自覺嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하아, 보나 마나 이것도 최고 관리자의 생각이었겠지?","JPN":"はあ……どうせこれも最高管理者の計画のうちだろう。","ENG":"*Sigh* No doubt this was the Supreme Administrator's idea too.","TWN":"唉，看來這肯定也是最高管理者的想法吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아무튼 물렁해 빠져가지고…….","JPN":"まったく、考えが甘いんだから……","ENG":"You're soft. Hopelessly soft...","TWN":" 總之真軟弱……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"……르네 말루프인가.","JPN":"……ルネ・マルーフか。","ENG":"...Renée Maalouf.","TWN":"……是芮妮瑪盧夫嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"시스템을 구축해야 하니 서둘러라.","JPN":"システムを構築せねばならない。急げ。","ENG":"We must build the system. Make haste.","TWN":"還得建立系統，趕快行動吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……아무리 생각해도 이해가 안 되네.","JPN":"……どう考えても理解できない。","ENG":"No matter how I think about it, this makes no sense.","TWN":"……無論我怎麼想都想不通。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"말루프 아줌마?","JPN":"マルーフおばさん？","ENG":"Old hag Maalouf?","TWN":"瑪盧夫大嬸？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여긴 어떻게 온 거야? 로터스에 있다고 듣기는 했는데…….","JPN":"なんでここにいるの？　ロータスにいるって聞いてはいたけど……","ENG":"How did you get here? I only heard you were in Lotus...","TWN":"妳是怎麼來這裡的？聽說妳在羅特斯……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자, 그 자식. 대체 뭘 꾸미는 거야?","JPN":"最高管理者のやつ、いったい何を企んでいるんだ？","ENG":"That Supreme Administrator. What's he plotting?","TWN":"最高管理者那傢伙，到底在搞什麼鬼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"느닷없이 내 흑역사를 재현해달라고 하질 않나.","JPN":"突然私の黒歴史を再現してほしいと言い出すわ。","ENG":"He had me recreate my humiliating past out of the blue.","TWN":"突然要我重現自己的黑歷史。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"언제 사람을 죽일지 모르는 살육 기계를 관리국 격납고에 들이질 않나.","JPN":"いつ人を殺すかわからない殺戮マシーンを管理局の格納庫に入らせるわ。","ENG":"Then brought a killing machine that could murder at any moment into the Administration hangar.","TWN":"還把說不定會隨時把人殺了的殺戮機器送到管理局的機庫。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"범죄자든 시니어든 그런 게 뭐가 중요해?","JPN":"犯罪者とかシニアとか、今は関係ないよ。","ENG":"Criminal or Senior, who cares.","TWN":"不管是犯人還是Senior，這有什麼重要的？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"얼른 움직여.","JPN":"早く動いて。","ENG":"Move.","TWN":"快點行動。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"말루프 아줌마도 얼른 그라운드 원으로 가야 할 것 아냐?","JPN":"マルーフおばさんも、早くグラウンド・ワンに帰りたいんじゃないの？","ENG":"Old hag Maalouf, you also need to get to Ground One.","TWN":"瑪盧夫大嬸也得趕快去Ground 1吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"칫, 나도 알고 있으니까 그만 보채.","JPN":"ちっ、分かっているから急かすな。","ENG":"Tch. I know, so stop nagging me.","TWN":"哼，我知道了，別再催了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그리고 시니어 르네.","JPN":"それから、シニア・ルネだ。","ENG":"And it's Senior Renée.","TWN":"還有是Senior芮妮。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"윽, 알겠어. 시니어 르네.","JPN":"うっ……分かったよ。シニア・ルネ。","ENG":"Ugh. Fine. Senior Renée.","TWN":"唔，我知道了。Senior芮妮。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"선로전환기의 설계도는 나도 좀 봤었어.","JPN":"線路転換器の設計図は私も見せてもらった。","ENG":"I skimmed the Track Switcher blueprints.","TWN":"我也看過線路轉換器的設計圖。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"가동하는 방법은 파악했고, 난 상태를 확인하러 온 것 뿐이니까.","JPN":"稼働する方法も把握済みだし、私は様子を見に来ただけ。","ENG":"I grasped how to activate it. I’m just here to check its status.","TWN":"我知道如何啟動，只是來確認狀態而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 맘대로 하셔.","JPN":"ふん、好きにすれば。","ENG":"Hmph, do as you like.","TWN":"哼，隨便你怎麼說。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이볼브 원, 아티팩트 쪽 설계는 어때? 자칫 에너지가 새어 나가지 않을까?","JPN":"イボルブ・ワン、アーティファクト側の設計はどう？　エネルギーが漏れたりはしなそう？","ENG":"Evolved One, how's the design for the Artifact holding up? Any risk of energy leakage?","TWN":"Evolved One，遺物設計怎麼樣了？會不會洩漏能量？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이론적으로는 완벽한 설계다.","JPN":"理論上は完璧な設計だ。","ENG":"The design is theoretically perfect.","TWN":"理論上設計是完美的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이대로 완성된다면 선로전환기는 무사히 가동할 수 있을 것 같군.","JPN":"このまま完成すれば、線路転換器は無事稼働できるだろう。","ENG":"If completed as is, the Track Switcher should operate safely.","TWN":"照這樣完成的話，應該能順利啟動線路轉換器。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래? 다행이네.","JPN":"そう？　よかった。","ENG":"Really? Good.","TWN":"是嗎？那就好。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이 시스템 설계. 퓨처 앳 워의 여러 프로젝트를 참고해서 설계한 거거든.","JPN":"このシステム設計、フューチャーアットウォーの色んなプロジェクトを参考にして仕上げたものなんだよね。","ENG":"I referenced several Future-at-War projects for this system design.","TWN":"這個系統設計，參考了天啟兵器的各個專案。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 당시에는 차원 계면에 대한 연구가 이루어지지 않았을 텐데.","JPN":"あの頃はまだ次元界面の研究は進んでいなかったはずだが。","ENG":"Research on dimension surfaces did not exist back then.","TWN":"當時應該還沒有對次元界面進行研究。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"타이탄을 만들면서 이것저것 실험을 많이 해봤던데?","JPN":"タイタンの製作過程で色んな実験をしたみたい。","ENG":"They tried many experiments while building Titan.","TWN":"打造泰坦時不是做了各種實驗嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이터니움 드라이브의 반중력장을 이용하는 것도 거기서 처음 나온 거라며?","JPN":"エタニウムドライブの反重力場を利用するのも、そういう実験の産物なんでしょ？","ENG":"The anti-gravity field of the Eternium Drive first came from there, right?","TWN":"永恆之金引擎的反重力場，也是那時首次問世的啊？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 아이디어를 제시한 것도 엠버 소장이라고 들었어.","JPN":"そのアイデアを提示したのも、アンバー所長だったんだって。","ENG":"I heard Director Ember proposed that idea.","TWN":"我聽說提出那個點子也是琥珀所長。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하… 직접 만나서 얘기할 수 있으면 정말 좋을 텐데.","JPN":"はあ……直接会って話せたらいいのになあ。","ENG":"*Sigh...* I wish I could meet and talk to her in person.","TWN":"哈……真希望能親自跟她見面聊聊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"꿈 깨.","JPN":"諦めろ。","ENG":"Wake up.","TWN":"醒醒吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"내가 그 인간을 찾으려고 시니어 자리에 오르자마자 동원할 수 있는 모든 정보원을 동원했어.","JPN":"あの人を探すために、私はシニアになるや否や使える情報員を総動員した。","ENG":"When I became Senior, I used every source I had to try and find her.","TWN":"我一升上Senior的職位，就動用所有可用情報員尋找那個人。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 사람이 증발이라도 한 것처럼 사라졌더군.","JPN":"しかし、まるで蒸発でもしたかのように、完全に姿を消していた。","ENG":"Yet she vanished as if she evaporated.","TWN":"可她就像人間蒸發一樣消失了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"피치 못할 사정이 있었겠지.","JPN":"きっとやむを得ない事情があったんだよ。","ENG":"There must have been circumstances.","TWN":"她肯定有不得已的原因。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사람들을 구하기 위해서 무단 반출까지 강행했던 사람이 그렇게 사라졌을 리 없잖아.","JPN":"市民を助けるために無断搬出まで強行した人が、勝手に消えるはずがないよ。","ENG":"A person who risked smuggling Titan out to save people would not just disappear.","TWN":"為了救人、不惜違規擅自調出設備的人，不可能就這樣消失。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……이거 하나는 인정할게.","JPN":"……これだけは認める。","ENG":"...Alright, I’ll give you that one.","TWN":"……這點我同意。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 사람이 지금까지 우리와 함께했다면 분명 많은 걸 바꿨을지도 몰라.","JPN":"彼女が今日まで私たちと一緒に歩んでいたら、きっと多くの変化をもたらしていただろう。","ENG":"If she had stayed with us, she might've changed much.","TWN":"如果那個人一直和我們同在，肯定能改變很多事。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"뭔가 착각하고 있군. 정정을 요청하지.","JPN":"何か勘違いをしているな。訂正を要求する。","ENG":"You are mistaken. Allow me to correct you.","TWN":"妳似乎誤會什麼了，需要更正。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L19_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"……엠버 소장은 패배자였다.","JPN":"……アンバー所長は負け犬だった。","ENG":"...Director Ember was a failure.","TWN":"……琥珀所長是個失敗者。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"자신의 허황된 꿈을 자식들에게, 동료들에게 멋대로 떠맡겨버리고는…….","JPN":"己の愚かな夢を子どもたちに、同僚たちに押しつけておいて……","ENG":"She dumped her grand dream onto her children and colleagues as she pleased.","TWN":"她把自己荒謬的夢想，隨便丟給子女和同事……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"정작 본인은 꿈꾸길 포기하고 도망쳤지.","JPN":"当の本人は夢見ることを諦めて逃げた。","ENG":"Then she gave up dreaming and ran away.","TWN":"自己卻放棄夢想逃跑了。"},"stage":{"bg":"HORIZON_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L25_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그렇기 때문에 인간의 가능성은 한계가 있고, 무의미하다는 결론을 내렸다.","JPN":"それゆえ、人間の可能性には限界があり、無意味なものだという結論を出した。","ENG":"Hence I concluded human potential has limits and is meaningless.","TWN":"因此我認為人類的可能性有限、毫無意義。"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L26_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 가능성을 가장 믿고 있었던 자신조차.","JPN":"その可能性を最も信じていた所長本人でさえも……","ENG":"Even she, who believed in that potential most,","TWN":"就連最相信那個可能性的人，"},"stage":{"bg":"SS_SCAVENGER_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"유기체의 나약한 한계에 부딪혀 무너져 내리고 말았으니까.","JPN":"有機体の脆弱さという限界を前にして、崩れ落ちてしまったからな。","ENG":"collapsed at the fragile limits of an organic being.","TWN":"也因為到達有機體的脆弱臨界點而崩潰。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나도 몇 가지 정정해 줄 게 있어.","JPN":"私もいくつか訂正していい？","ENG":"I have corrections too.","TWN":"我也要更正幾點。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신은 패배자라고 생각할지 몰라도, 우리가 꾸었던 꿈은 진짜라고.","JPN":"あなたは彼女を負け犬だと思っているかもしれないけど、私たちが見た夢は本物だった。","ENG":"You may think she failed, yet the dream we dreamed is real.","TWN":"你或許認為她是失敗者，但我們做過的夢是真的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……혹시라도 엠버 소장과 대화할 일이 생기면 전해줘.","JPN":"……もしアンバー所長と話す機会があれば伝えて。","ENG":"...If you ever get to speak with Director Ember, tell her this.","TWN":"……如果哪天有機會和琥珀所長對話，請轉告她。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"20년 전, 당신이 흩뿌린 씨앗들은 지금 이 자리에서 성공적으로 피어날 거라고.","JPN":"20年前、あなたが蒔いた種はこの場で見事に花を咲かせるって。","ENG":"The seeds you scattered twenty years ago are blooming successfully here and now.","TWN":"20年前妳撒下的種子，現在正成功在這裡生根。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 반드시, 그렇게 만들 거야.","JPN":"絶対、私がそうさせてみせるから。","ENG":"I will make sure of it.","TWN":"我一定會讓它實現。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간의 힘이란 건 결국 그 정도다.","JPN":"人間の力というのは、所詮その程度だ。","ENG":"That is the limitation of humans.","TWN":"人類的力量，大概也就這樣了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간이라는 개체는 미약하다. 세계가 강요하는 운명에 반드시 패배하게 되어 있지.","JPN":"人間という個体は脆弱だ。世界が強要する運命には必ず屈する運命にある。","ENG":"Humans are frail. They always succumb to the fate imposed by the world.","TWN":"人類這種個體很脆弱，必定會在世界強加的命運下失敗。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 동시에 하나하나가 가능성을 내포한 작은 세계.","JPN":"しかし、それと同時に一人一人が可能性を秘めている小さな世界。","ENG":"But simultaneously, it is a small world with infinite possibilities.","TWN":"但同時，每個人都是潛藏可能性的小小世界。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너희가 가진 숙명이 모인다면, 세계의 운명도 한 번 정도는 바꿀 수 있겠지.","JPN":"お前たち一人一人の宿命が集まれば、世界の運命も一度ぐらいなら変えられるだろう。","ENG":"Perhaps a collection of humans' destinies has the power to alter the fate of the world once.","TWN":"當你們的命運聚集，或許能改變一次世界的命運。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 실패했지만 너희들은 다르길 기대한다.","JPN":"私は失敗したが、お前たちは違うことを期待している。","ENG":"I have failed, but I hope the outcome is different for you.","TWN":"我失敗了，但希望你們不同。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだな。","ENG":"Very well.","TWN":"嗯。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나 역시 운명의 변곡점을 확인하기 위해, 이곳에 온 거니까.","JPN":"私もまた、運命の変曲点を確認するためにここに来ている。","ENG":"I came here to witness that inflection point of fate.","TWN":"我也是為了確認命運的轉折點，才會來到這裡。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥, 악당 주제에 기대를 확인하느니 마느니, 우습네.","JPN":"ふん、悪党のくせに期待を確認するだの何だの、笑わせてくれる。","ENG":"Hmph. For a villain to prattle about confirming expectations. Ridiculous.","TWN":"哼，身為一個壞蛋還談什麼期望，真可笑。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"씨앗이라…….","JPN":"種、か……","ENG":"Seeds, huh...","TWN":"種子嗎……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"수송편을 준비해 둬.","JPN":"輸送船を準備しておけ。","ENG":"Prepare transport.","TWN":"準備運輸工具。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"알겠습니다. 시니어님.","JPN":"かしこまりました、シニア。","ENG":"Understood, Senior.","TWN":"我知道了，Senior。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자와 함께 돌아간다.","JPN":"最高管理者と共に帰還する。","ENG":"We return with the Supreme Administrator.","TWN":"和最高管理者一起回去。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원으로.","JPN":"グラウンド・ワンへ。","ENG":"To Ground One.","TWN":"前往Ground 1。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};